export interface MiniAppManifest {
  appId?: string;
  permissions?: string[];
}

export const MiniApp: {
  meta: {
    sdkVersion: string;
    appId: string | null;
    instanceId: string | null;
  };
  capabilities: string[];
  
  init(manifest: MiniAppManifest): Promise<any>;
  getCapabilities(): Promise<string[]>;
  
  notify(options: { title?: string; message: string }): Promise<any>;
  pay(options: { amount: number; currency: string; description?: string }): Promise<any>;
  
  auth: {
    login(): Promise<{ id?: string; name?: string; token?: string }>;
    getProfile(): Promise<any>;
    getToken(options?: any): Promise<any>;
    logout(): Promise<any>;
  };
  
  storage: {
    setItem(key: string, value: any): Promise<any>;
    getItem(key: string): Promise<any>;
    removeItem(key: string): Promise<any>;
    clear(): Promise<any>;
    getQuota(): Promise<any>;
  };
  
  ui: {
    showModal(options: { title?: string; message?: string; content?: string }): Promise<{ confirmed: boolean }>;
    modal(options: any): Promise<any>;
    toast(options: { message: string }): Promise<any>;
    loading: {
      show(options?: any): Promise<any>;
      hide(): Promise<any>;
    };
  };
  
  payments: {
    requestPayment(req: any): Promise<any>;
  };
  
  navigation: {
    open(options: any): Promise<any>;
    back(options?: any): Promise<any>;
    setTitle(title: string): Promise<any>;
  };
  
  device: {
    clipboard: {
      writeText(text: string): Promise<any>;
      readText(): Promise<{ text: string }>;
    };
    location: {
      getCurrentPosition(options?: any): Promise<{ lat: number; lng: number; accuracy: number }>;
      watchPosition(options?: any): Promise<{ watchId: string }>;
      clearWatch(watchId: string): Promise<any>;
    };
    scanner: {
      scan(options?: any): Promise<{ text: string; format: string }>;
    };
    file: {
      pick(options?: any): Promise<{ name: string; size: number; type: string }>;
    };
    camera: {
      open(options?: any): Promise<{ url: string }>;
    };
  };
  
  permissions: {
    query(scope: string): Promise<any>;
    request(scopes: string[]): Promise<Record<string, string>>;
  };

  on(name: string, callback: (data: any) => void): void;
  emit(name: string, data: any): void;
  
  onLaunch(callback: () => void): void;
  onShow(callback: () => void): void;
  onHide(callback: () => void): void;
  onClose(callback: () => void): void;
};
